form:Form.form:Scripts:
		function LoadForm()
{
	if(!Ctrl("LIST"))
	{
		Ctrl('licencia').SetXValue("0");
		if(Ctrl('oi_licencia').GetXValue() != ""  && Ctrl('oi_licencia').GetXValue() != "0" && Ctrl('l_art').GetXValue() != "1")
			Ctrl('licencia').SetXValue("1");		
	}  

	if(Ctrl('f_fechahora_alta'))
		Ctrl('f_alta').SetXValue(Ctrl('f_fechahora_alta').GetXValue());
	if(Ctrl('f_fechahora_baja'))
		Ctrl('f_baja').SetXValue(Ctrl('f_fechahora_baja').GetXValue());		

}  

function ValModif(me)
{
	if (Ctrl('main').GetMode()=="EDIT")  
	{
 		var licencia,licencia_art,o_licencia_per;				
 		np = new NomadProxy("", ut);
 		var nSQL = np.SQLService();   
 		licencia = nSQL.GetOBJ(Ctrl("main").getResource("QRY_LICENCIA"), "<PARAM oi_licencia=\""+Ctrl("oi_licencia").GetXValue()+"\" />"); 				 

		if(licencia.o_licencia_per == undefined) o_licencia_per = "";

		if(Ctrl('l_art').GetXValue() == "1")
		{ 
			if(Ctrl('oi_licencia_art').GetXValue() != "" && Ctrl('oi_licencia_art').GetXValue() != "0" && Ctrl('oi_licencia').GetXValue() != "" && Ctrl('oi_licencia').GetXValue() != "0")	
			{   
				if(Ctrl('f_alta').GetXValue() != Ctrl('f_fechahora_alta').GetXValue() || Ctrl('f_baja').GetXValue() != Ctrl('f_fechahora_baja').GetXValue() || Ctrl('o_accidente').GetXValue() != o_licencia_per) 
				{  
 					licencia_art = nSQL.GetOBJ(Ctrl("main").getResource("QRY_LICENCIA_ART"), "<PARAM oi_licencia_art=\""+Ctrl("oi_licencia_art").GetXValue()+"\" />"); 		

					if (parseInt(Ctrl("e_dias_perdidos").GetXValue(),10) <= 10)
					{						
						if (!confirm("El registro se encuentra asociado con dos licencias en el módulo de Personal con: fecha de inicio: " + licencia.f_inicio +" y fecha de fin "+ licencia.f_fin + " - Licencia a cargo de ART con fecha de inicio: " + licencia_art.f_inicio +" y fecha de fin "+ licencia_art.f_fin + " - Como la cantidad de dias es menor a 10 se liminara la licencia cte a ART. Confirma la modificación?"))
						{
							me.SetError('La operación no ha sido completada');
							return false;
						}				
					}
					else
					{					 
						if (!confirm("El registro se encuentra asociado con dos licencias en el módulo de Personal con: fecha de inicio: " + licencia.f_inicio +" y fecha de fin "+ licencia.f_fin + " - Licencia a cargo de ART con fecha de inicio: " + licencia_art.f_inicio +" y fecha de fin "+ licencia_art.f_fin + ". Confirma la modificación?"))
						{
							me.SetError('La operación no ha sido completada');
							return false;
						}				
					}
				}                         		
			}		  
			else if (Ctrl('oi_licencia').GetXValue() != "" && Ctrl('oi_licencia').GetXValue() != "0")
			{
				if(Ctrl('f_alta').GetXValue() != Ctrl('f_fechahora_alta').GetXValue() || Ctrl('f_baja').GetXValue() != Ctrl('f_fechahora_baja').GetXValue() || Ctrl('o_accidente').GetXValue() != o_licencia_per) 
				{
					if (parseInt(Ctrl("e_dias_perdidos").GetXValue(),10) <= 10)
					{
						if(!confirm('La Licencia por Accidente con fecha de inicio: ' + licencia.f_inicio +' y fecha de fin '+ licencia.f_fin +' será modificada. Desea continuar?'))
						{	
							me.SetError('La operación no ha sido completada');
							return false;
						} 
					}
					else
					{   
						if(!confirm('La Licencia por Accidente con fecha de inicio: ' + licencia.f_inicio +' y fecha de fin '+ licencia.f_fin +' será modificada. Al ser mas de 10 dias se creara la licencia a cargo de ART. Desea continuar?'))					
						{	
							me.SetError('La operación no ha sido completada');
							return false;
						} 				
					}		
				}
			}		
		}
		else
		{ 
			if(Ctrl('oi_licencia').GetXValue() != "" && Ctrl('oi_licencia').GetXValue() != "0")
			{
				if(Ctrl('f_alta').GetXValue() != Ctrl('f_fechahora_alta').GetXValue() || Ctrl('f_baja').GetXValue() != Ctrl('f_fechahora_baja').GetXValue() || Ctrl('o_accidente').GetXValue() != o_licencia_per) 
				{	
					if(confirm('La Licencia por Accidente con fecha de inicio: ' + licencia.f_inicio +' y fecha de fin '+ licencia.f_fin +' será modificada. Desea continuar?'))
					{	 
					    f_fin = Ctrl('f_fechahora_alta').GetXValue();
					    f_inicio = Ctrl('f_fechahora_baja').GetXValue(); 
					    oi_licencia = Ctrl('oi_licencia').GetXValue();
					    oi_personal_emp = Ctrl('oi_personal_emp').GetXValue();
					    dias = Ctrl('e_dias_perdidos').GetXValue();
						openNewFlow('NucleusRH.Base.Accidentabilidad.LegajoAccidentes.flow','validarEdit','<DATA oi_personal_emp="'+oi_personal_emp+'" oi_licencia="'+oi_licencia+'" f_inicio="'+f_inicio+'" f_fin="'+f_fin+'"  dias="'+dias+'" />', new validarResultado());                      
	 					valid = Ctrl('valid').GetXValue();   

						if(valid !="1")
						{
							me.SetError(Ctrl('alert').GetXValue());
		    				return false;
						}
						return true;

					}  
					else
					{
					    me.SetError('La operación no ha sido completada');
						return false;
					}
				}
			}		
		}		  
	}	      

	return true;	
}  

 function validarResultado()
{
	this.processResult = function(XML)
	{                 
		var myRESULT=new NomadXML(XML);   

		Ctrl("valid").SetXValue(myRESULT.GetAttr("valid"));
		Ctrl("alert").SetXValue(myRESULT.GetAttr("alert"));
	}
}        

function ValidarSolapamiento(myThis)
{	   
	if (CtrlExists("l_bloqueada") && (Ctrl("l_bloqueada").GetXValue()=="1")) return true;
	if (Ctrl("main").GetLastDoc("OBJ2")?false:true) return true;

	var MyLIQPER=new NomadXML(Ctrl("main").GetLastDoc("OBJ2"));  

	var t;
	var f_inicio, f_fin;

	if (!CtrlExists("LIST"))
		for (var cur = MyLIQPER.FirstChild(); cur!=null; cur=cur.Next())
		{
			if (cur.GetAttr("nmd-status").substr(0, 3) == "~d,") continue;
			if (cur.GetAttr("nmd-status").substr(0, 3) == "~x,") continue;

			if (CtrlExists("e_id") && cur.GetAttr("id")==Ctrl("e_id").GetXValue()) continue;

			f_inicio=cur.GetAttrDateTime("F_FECHAHORA_BAJA");
			f_fin=cur.GetAttrDateTime("F_FECHAHORA_ALTA");

			if (Ctrl("f_fechahora_baja").TypedValue() > f_fin) continue;
			if (Ctrl("f_fechahora_alta").TypedValue() < f_inicio) continue;

			myThis.SetError("La licencia actual se solapa con otra licencia del " + formatDate(f_inicio, "dd/mm/yyyy") + " al " + formatDate(f_fin, "dd/mm/yyyy"));
			return false;
		}             

	return true;
}

function ValDel()
{

	if(Ctrl("oi_licencia").GetXValue() != "" && Ctrl("oi_licencia_art").GetXValue() != "")	
	{             
		var licencia,licencia_art;				
 		np = new NomadProxy("", ut);
 		var nSQL = np.SQLService();   
 		licencia = nSQL.GetOBJ(Ctrl("main").getResource("QRY_LICENCIA"), "<PARAM oi_licencia=\""+Ctrl("oi_licencia").GetXValue()+"\" />"); 		
 		licencia_art = nSQL.GetOBJ(Ctrl("main").getResource("QRY_LICENCIA_ART"), "<PARAM oi_licencia_art=\""+Ctrl("oi_licencia_art").GetXValue()+"\" />"); 				

		if (!confirm("El registro se encuentra asociado con dos licencias en el módulo de Personal con: fecha de inicio: " + licencia.f_inicio +" y fecha de fin "+ licencia.f_fin + " y con fecha de inicio: " + licencia_art.f_inicio +" y fecha de fin "+ licencia_art.f_fin + ". Confirma la eliminación?"))		
		{
			me.SetError('La operación no ha sido completada');
			return false;
		} 
		Ctrl("listdels").AddRow().SetAttr("id",(Ctrl("oi_licencia").GetXValue()));
		Ctrl("listdels").AddRow().SetAttr("id",(Ctrl("oi_licencia_art").GetXValue()));		
	}

	else if(Ctrl("oi_licencia").GetXValue() != "")	
	{
		var licencia;				
 		np = new NomadProxy("", ut);
 		var nSQL = np.SQLService();   
 		licencia = nSQL.GetOBJ(Ctrl("main").getResource("QRY_LICENCIA"), "<PARAM oi_licencia=\""+Ctrl("oi_licencia").GetXValue()+"\" />"); 		

		if (!confirm("El registro se encuentra asociado con una licencia en el módulo de Personal con fecha de inicio: " + licencia.f_inicio +" y fecha de fin "+ licencia.f_fin + ". Confirma la eliminación?"))
		{
			me.SetError('La operación no ha sido completada');
			return false;
		} 
		Ctrl("listdels").AddRow().SetAttr("id",(Ctrl("oi_licencia").GetXValue()));		
	}

	return true;	
}

function CalcularDias()
{
 	if (Ctrl('f_fechahora_alta').GetXValue() != "" && Ctrl('f_fechahora_baja').GetXValue() != "")
 	{ 		
 		if (Ctrl('f_fechahora_alta').GetXValue() >= Ctrl('f_fechahora_baja').GetXValue())
 			Ctrl('e_dias_perdidos').SetTypedValue(DiffDays(Ctrl('f_fechahora_alta').TypedValue(), Ctrl('f_fechahora_baja').TypedValue()));
 		else
 		{
 			alert("La fecha de alta del empleado debe ser mayor a la fecha de baja");
 			return false; 
 		}
  }
}
